--

COMMENT ON TABLE core.login_rate_limit_failures IS 'W4.7/EM5 — sliding-window login-failure counter shared across admin-api replicas. One row per failed attempt keyed on the trusted client IP; pruned opportunistically past max(window, lockout).';


