    payload_sha256 text NOT NULL,
    mutex_id uuid,
    CONSTRAINT ck_review_jobs_payload_schema_version CHECK ((job_payload_schema_version = 1)),
    CONSTRAINT ck_review_jobs_payload_sha256_hex CHECK ((payload_sha256 ~ '^[0-9a-f]{64}$'::text)),
